# tests/evals/conftest.py (add to pytest_configure)
def pytest_configure(config):
    shard = int(config.getoption("--shard", default="1"))
    total = int(config.getoption("--total-shards", default="1"))
    if total > 1:
        import time
        # Stagger: shard N waits N-1 seconds before first request
        stagger = (shard - 1) * 2
        if stagger:
            time.sleep(stagger)
